import React from 'react';
import { getProductName, getImagePath } from '../utils';

interface ProductCardProps {
  categoryPath: string;
  imageName: string;
  quantity?: string;
  onQuantityChange?: (imagePath: string, value: string) => void;
  showQuantityInput?: boolean;
  readOnly?: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({
  categoryPath,
  imageName,
  quantity = '',
  onQuantityChange,
  showQuantityInput = true,
  readOnly = false
}) => {
  const imagePath = getImagePath(categoryPath, imageName);
  const productName = getProductName(imageName);

  return (
    <div style={{ width: 200, marginBottom: 'var(--space-2)' }}>
      <img
        src={process.env.PUBLIC_URL + `/MichiganState/${imagePath}`}
        alt={imageName}
        style={{ width: '100%', borderRadius: 'var(--radius)', boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}
      />
      <div style={{ fontSize: 12, marginTop: 4, marginBottom: 4 }}>{productName}</div>
      {showQuantityInput && !readOnly && (
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <label htmlFor={`qty-${imagePath}`} style={{ fontSize: 12, fontWeight: 'bold' }}>
            Qty:
          </label>
          <input
            type="number"
            id={`qty-${imagePath}`}
            min="0"
            value={quantity}
            onChange={(e) => onQuantityChange?.(imagePath, e.target.value)}
            style={{
              width: '60px',
              padding: '4px',
              border: '1px solid #ccc',
              borderRadius: 'var(--radius)',
              fontSize: '12px'
            }}
            required
          />
        </div>
      )}
      {readOnly && (
        <div style={{ fontWeight: 'bold', fontSize: 14 }}>Qty: {quantity}</div>
      )}
    </div>
  );
};

export default ProductCard;
